import heapq

def solve(n: int, edges: list[list[int]]) -> int:
    adj = [[] for _ in range(n)]
    for u, v, s, e in edges:
        adj[u].append((v, s, e))
    dist = [float('inf')] * n
    dist[0] = 0
    heap = [(0, 0)]
    while heap:
        time, u = heapq.heappop(heap)
        if u == n - 1:
            return time
        if time > dist[u]:
            continue
        for v, s, e in adj[u]:
            earliest = max(time, s)
            if earliest <= e:
                new_time = earliest + 1
                if new_time < dist[v]:
                    dist[v] = new_time
                    heapq.heappush(heap, (new_time, v))
    return -1
